import React, { useState, useEffect, useRef } from "react";
import { FaInstagram, FaWhatsapp, FaFacebook, FaMapMarkerAlt, FaArrowRight, FaStar, FaShieldAlt, FaBolt, FaHome } from "react-icons/fa";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Clash+Display:wght@400;500;600;700&family=Syne:wght@400;600;700;800&family=DM+Sans:ital,wght@0,300;0,400;0,500;1,300&display=swap');

  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  :root {
    --black: #0a0a0f;
    --ink: #12121a;
    --card: #16161f;
    --card2: #1c1c28;
    --border: rgba(255,255,255,0.07);
    --white: #f5f4ef;
    --cream: #ede9df;
    --accent: #c8f04d;
    --accent2: #7df3b8;
    --muted: rgba(245,244,239,0.45);
    --muted2: rgba(245,244,239,0.2);
    --grad: linear-gradient(135deg, #c8f04d 0%, #7df3b8 100%);
  }

  html { scroll-behavior: smooth; }

  body {
    background: var(--black);
    color: var(--white);
    font-family: 'DM Sans', sans-serif;
    overflow-x: hidden;
    -webkit-font-smoothing: antialiased;
  }

  /* ─── NAVBAR ─── */
  .rs-nav {
    position: fixed; top: 0; left: 0; right: 0; z-index: 100;
    display: flex; align-items: center; justify-content: space-between;
    padding: 22px 48px;
    background: rgba(10,10,15,0.7);
    backdrop-filter: blur(20px);
    border-bottom: 1px solid var(--border);
    transition: padding .3s;
  }
  .rs-logo {
    font-family: 'Syne', sans-serif;
    font-weight: 800; font-size: 1.5rem;
    background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    letter-spacing: -0.5px;
  }
  .rs-nav-links { display: flex; gap: 36px; align-items: center; }
  .rs-nav-links a {
    text-decoration: none; color: var(--muted); font-size: .9rem;
    letter-spacing: 0.02em; transition: color .2s;
    font-weight: 400;
  }
  .rs-nav-links a:hover { color: var(--white); }
  .rs-nav-cta {
    background: var(--accent); color: var(--black);
    border: none; padding: 10px 22px; border-radius: 50px;
    font-family: 'DM Sans', sans-serif; font-weight: 600;
    font-size: .85rem; cursor: pointer; transition: opacity .2s, transform .2s;
    letter-spacing: 0.01em;
  }
  .rs-nav-cta:hover { opacity: .85; transform: translateY(-1px); }

  /* ─── HERO ─── */
  .rs-hero {
    min-height: 100vh;
    display: flex; flex-direction: column; justify-content: center;
    padding: 140px 48px 80px;
    position: relative; overflow: hidden;
    background: var(--black);
  }
  .rs-hero-bg {
    position: absolute; inset: 0; pointer-events: none;
  }
  .rs-blob {
    position: absolute; border-radius: 50%; filter: blur(100px); opacity: .18;
  }
  .rs-blob-1 { width: 600px; height: 600px; background: var(--accent); top: -100px; right: -100px; }
  .rs-blob-2 { width: 400px; height: 400px; background: var(--accent2); bottom: 0; left: -80px; }

  .rs-hero-tag {
    display: inline-flex; align-items: center; gap: 8px;
    border: 1px solid var(--border); border-radius: 50px;
    padding: 7px 16px; width: fit-content;
