    color: var(--white); font-family: 'DM Sans', sans-serif;
    font-size: .95rem; font-weight: 300;
  }
  .rs-search-bar input::placeholder { color: var(--muted2); }
  .rs-search-bar select {
    background: transparent; border: none; outline: none;
    color: var(--muted); font-family: 'DM Sans', sans-serif;
    font-size: .88rem; padding: 0 16px; cursor: pointer;
    border-left: 1px solid var(--border); height: 40px;
  }
  .rs-search-bar select option { background: var(--ink); }
  .rs-search-btn {
    background: var(--accent); color: var(--black); border: none;
    padding: 14px 28px; border-radius: 10px; font-family: 'DM Sans', sans-serif;
    font-weight: 600; cursor: pointer; white-space: nowrap;
    transition: opacity .2s, transform .2s; font-size: .9rem;
  }
  .rs-search-btn:hover { opacity: .85; transform: scale(.98); }

  .rs-tabs {
    display: flex; gap: 8px; margin-bottom: 0; margin-top: 28px;
    animation: fadeUp .7s .35s ease both;
  }
  .rs-tab {
    background: transparent; border: 1px solid var(--border);
    color: var(--muted); padding: 8px 20px; border-radius: 50px;
    cursor: pointer; font-family: 'DM Sans', sans-serif;
    font-size: .85rem; transition: all .2s; font-weight: 400;
  }
  .rs-tab.active {
    background: var(--accent); border-color: var(--accent);
    color: var(--black); font-weight: 600;
  }

  /* ─── STATS ─── */
  .rs-stats {
    display: flex; gap: 1px;
    background: var(--border);
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
  }
  .rs-stat {
    flex: 1; padding: 40px 48px; background: var(--black);
    display: flex; flex-direction: column; gap: 6px;
    position: relative; overflow: hidden; transition: background .2s;
  }
  .rs-stat:hover { background: var(--card); }
  .rs-stat h2 {
    font-family: 'Clash Display', sans-serif;
    font-size: 2.8rem; font-weight: 700;
    background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    line-height: 1;
  }
  .rs-stat p { color: var(--muted); font-size: .9rem; letter-spacing: 0.02em; }

  /* ─── SECTION LABEL ─── */
  .rs-label {
    font-size: .75rem; text-transform: uppercase; letter-spacing: .12em;
    color: var(--accent); font-weight: 600; margin-bottom: 12px;
  }
  .rs-section-h2 {
    font-family: 'Clash Display', sans-serif;
    font-size: clamp(2rem, 4vw, 3rem);
    font-weight: 600; letter-spacing: -0.03em; line-height: 1.1;
    color: var(--white);
  }

  /* ─── LOCATIONS ─── */
  .rs-locations { padding: 100px 48px; }
  .rs-loc-grid {
    display: grid; grid-template-columns: repeat(4, 1fr);
    gap: 16px; margin-top: 44px;
  }
  .rs-loc-card {
    background: var(--card); border: 1px solid var(--border);
    border-radius: 16px; padding: 32px 28px;
    display: flex; align-items: center; justify-content: space-between;
    cursor: pointer; transition: all .25s; position: relative; overflow: hidden;
  }
  .rs-loc-card::before {
    content: ''; position: absolute; inset: 0;
    background: var(--grad); opacity: 0; transition: opacity .25s;
  }
  .rs-loc-card:hover { border-color: var(--accent); transform: translateY(-4px); }
  .rs-loc-card:hover::before { opacity: .04; }
  .rs-loc-card span {
    font-family: 'Syne', sans-serif; font-weight: 600;
    font-size: 1rem; letter-spacing: -0.01em; position: relative;
  }
  .rs-loc-icon { color: var(--muted2); font-size: .9rem; transition: color .25s; position: relative; }
  .rs-loc-card:hover .rs-loc-icon { color: var(--accent); }

  /* ─── TYPES ─── */
  .rs-types { padding: 0 48px 100px; }
  .rs-type-grid {
    display: grid; grid-template-columns: repeat(3, 1fr);
    gap: 20px; margin-top: 44px;
  }
  .rs-type-card {
    position: relative; border-radius: 20px; overflow: hidden;
    aspect-ratio: 4/3; cursor: pointer;
    border: 1px solid var(--border);
