  }
  .rs-type-card:hover { transform: scale(1.02); }
  .rs-type-card img {
    width: 100%; height: 100%; object-fit: cover;
    transition: transform .5s; filter: brightness(.65) saturate(.8);
  }
  .rs-type-card:hover img { transform: scale(1.08); filter: brightness(.5) saturate(.8); }
  .rs-type-label {
    position: absolute; bottom: 0; left: 0; right: 0;
    padding: 32px 24px 24px;
    background: linear-gradient(to top, rgba(0,0,0,.85) 0%, transparent 100%);
    display: flex; align-items: flex-end; justify-content: space-between;
  }
  .rs-type-label span {
    font-family: 'Clash Display', sans-serif;
    font-size: 1.4rem; font-weight: 600; letter-spacing: -0.02em;
  }
  .rs-type-arr {
    width: 36px; height: 36px; border-radius: 50%;
    background: rgba(255,255,255,.1); backdrop-filter: blur(6px);
    display: flex; align-items: center; justify-content: center;
    font-size: .8rem; color: var(--white); opacity: 0;
    transition: opacity .2s; border: 1px solid rgba(255,255,255,.2);
  }
  .rs-type-card:hover .rs-type-arr { opacity: 1; }

  /* ─── FEATURED ─── */
  .rs-featured { padding: 0 48px 100px; }
  .rs-scroll-row {
    display: grid; grid-template-columns: repeat(3, 1fr);
    gap: 20px; margin-top: 44px;
  }
  .rs-scroll-card {
    background: var(--card); border: 1px solid var(--border);
    border-radius: 20px; overflow: hidden; cursor: pointer;
    transition: all .3s; position: relative;
  }
  .rs-scroll-card:hover { border-color: rgba(200,240,77,.3); transform: translateY(-6px); box-shadow: 0 24px 60px rgba(0,0,0,.4); }
  .rs-scroll-card img {
    width: 100%; height: 220px; object-fit: cover;
    filter: brightness(.8); transition: filter .3s, transform .5s;
  }
  .rs-scroll-card:hover img { filter: brightness(.7); transform: scale(1.04); }
  .rs-card-info { padding: 20px 24px 24px; }
  .rs-card-info h4 {
    font-family: 'Syne', sans-serif; font-size: 1.05rem;
    font-weight: 700; letter-spacing: -0.01em; margin-bottom: 6px;
  }
  .rs-card-loc { color: var(--muted); font-size: .85rem; display: flex; align-items: center; gap: 5px; }
  .rs-card-price {
    font-family: 'Clash Display', sans-serif;
    font-size: 1.3rem; font-weight: 600;
    background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent;
    margin-top: 12px;
  }
  .rs-card-badge {
    position: absolute; top: 14px; left: 14px;
    background: rgba(10,10,15,.7); backdrop-filter: blur(8px);
    border: 1px solid var(--border); border-radius: 50px;
    padding: 4px 12px; font-size: .72rem; color: var(--accent);
    font-weight: 600; letter-spacing: 0.05em; text-transform: uppercase;
  }

  /* ─── CITY BANNER ─── */
  .rs-city {
    margin: 0 48px; border-radius: 24px; overflow: hidden;
    position: relative; height: 260px;
    display: flex; align-items: center; justify-content: center;
    margin-bottom: 100px;
    background: var(--card2); border: 1px solid var(--border);
  }
  .rs-city-inner {
    position: relative; z-index: 2; text-align: center;
  }
  .rs-city h2 {
    font-family: 'Clash Display', sans-serif;
    font-size: clamp(2rem, 4vw, 3.5rem);
    font-weight: 700; letter-spacing: -0.03em;
  }
  .rs-city-dots {
    position: absolute; inset: 0; overflow: hidden; opacity: .15;
    background-image: radial-gradient(circle, #c8f04d 1px, transparent 1px);
    background-size: 40px 40px;
  }

  /* ─── HIGHLIGHTS ─── */
  .rs-highlights { padding: 0 48px 100px; }
  .rs-hl-grid {
    display: grid; grid-template-columns: repeat(3, 1fr);
    gap: 20px; margin-top: 44px;
  }
  .rs-hl-card {
    background: var(--card); border: 1px solid var(--border);
    border-radius: 20px; padding: 40px 32px;
    display: flex; flex-direction: column; gap: 16px;
    transition: border-color .25s; position: relative; overflow: hidden;
  }
  .rs-hl-card:hover { border-color: rgba(200,240,77,.3); }
  .rs-hl-icon {
    width: 48px; height: 48px; border-radius: 14px;
    background: rgba(200,240,77,.1); display: flex; align-items: center;
    justify-content: center; font-size: 1.2rem; color: var(--accent);
    border: 1px solid rgba(200,240,77,.2);
  }
  .rs-hl-card h3 {
    font-family: 'Syne', sans-serif; font-size: 1.2rem;
    font-weight: 700; letter-spacing: -0.01em;
  }
  .rs-hl-card p { color: var(--muted); font-size: .9rem; line-height: 1.65; }

  /* ─── TESTIMONIAL ─── */
  .rs-testi { padding: 0 48px 100px; }
  .rs-testi-card {
    background: var(--card); border: 1px solid var(--border);
    border-radius: 24px; padding: 60px;
    display: flex; flex-direction: column; gap: 24px;
    max-width: 700px; margin: 44px auto 0; text-align: center; align-items: center;
    position: relative; overflow: hidden;
  }
  .rs-testi-card::before {
    content: '"';
    position: absolute; top: -20px; left: 40px;
    font-family: 'Clash Display', sans-serif; font-size: 14rem;
    color: rgba(200,240,77,.04); line-height: 1; pointer-events: none;
  }
  .rs-stars { display: flex; gap: 4px; color: var(--accent); font-size: .9rem; }
  .rs-testi-card p {
    font-size: 1.15rem; line-height: 1.7; color: var(--white);
    font-style: italic; font-weight: 300; position: relative;
  }
  .rs-testi-card h4 { color: var(--muted); font-size: .85rem; font-weight: 400; }

  /* ─── CTA ─── */
  .rs-cta {
    margin: 0 48px 100px;
    border-radius: 28px; overflow: hidden;
    background: var(--accent);
    padding: 80px; display: flex; align-items: center;
    justify-content: space-between; gap: 40px;
    position: relative;
  }
  .rs-cta::before {
    content: ''; position: absolute; inset: 0;
    background: radial-gradient(ellipse at top right, rgba(125,243,184,.5) 0%, transparent 60%);
    pointer-events: none;
  }
  .rs-cta-left { position: relative; }
  .rs-cta h2 {
    font-family: 'Clash Display', sans-serif;
    font-size: clamp(2rem, 3.5vw, 3rem);
    color: var(--black); font-weight: 700; letter-spacing: -0.03em; line-height: 1.1;
  }
  .rs-cta p { color: rgba(10,10,15,.6); margin-top: 12px; font-size: 1rem; }
  .rs-cta-btn {
    background: var(--black); color: var(--white); border: none;
    padding: 18px 36px; border-radius: 14px;
    font-family: 'Syne', sans-serif; font-weight: 700;
    font-size: 1rem; cursor: pointer; white-space: nowrap;
    display: flex; align-items: center; gap: 10px;
    position: relative; transition: opacity .2s, transform .2s;
    flex-shrink: 0;
  }
  .rs-cta-btn:hover { opacity: .88; transform: scale(.98); }

  /* ─── FOOTER ─── */
  .rs-footer {
    border-top: 1px solid var(--border);
    padding: 40px 48px;
    display: flex; align-items: center; justify-content: space-between;
  }
  .rs-footer-logo {
    font-family: 'Syne', sans-serif; font-weight: 800; font-size: 1.1rem;
    background: var(--grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  }
  .rs-footer p { color: var(--muted); font-size: .85rem; }
  .rs-socials { display: flex; gap: 16px; }
  .rs-socials a {
    width: 38px; height: 38px; border-radius: 50%;
    border: 1px solid var(--border); background: var(--card);
    display: flex; align-items: center; justify-content: center;
    color: var(--muted); text-decoration: none; font-size: .9rem;
    transition: all .2s;
  }
  .rs-socials a:hover { border-color: var(--accent); color: var(--accent); }

  /* ─── ANIMATIONS ─── */
  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(24px); }
    to { opacity: 1; transform: translateY(0); }
  }
  @keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: .3; }
  }

  /* ─── RESPONSIVE ─── */
  @media (max-width: 900px) {
    .rs-nav { padding: 18px 24px; }
    .rs-hero { padding: 120px 24px 60px; }
    .rs-stats { flex-direction: column; }
    .rs-loc-grid, .rs-type-grid, .rs-scroll-row, .rs-hl-grid { grid-template-columns: 1fr 1fr; }
    .rs-locations, .rs-types, .rs-featured, .rs-highlights, .rs-testi { padding-left: 24px; padding-right: 24px; }
    .rs-city, .rs-cta { margin-left: 24px; margin-right: 24px; }
    .rs-cta { flex-direction: column; padding: 48px 36px; align-items: flex-start; }
    .rs-footer { flex-direction: column; gap: 20px; text-align: center; padding: 32px 24px; }
  }

  @media (max-width: 560px) {
    .rs-loc-grid, .rs-type-grid, .rs-scroll-row, .rs-hl-grid { grid-template-columns: 1fr; }
    .rs-hero-h1 { font-size: 2.8rem; }
    .rs-search-bar { flex-direction: column; border-radius: 14px; padding: 12px; gap: 8px; }
    .rs-search-bar select { border-left: none; border-top: 1px solid var(--border); padding: 8px 0; }
    .rs-search-btn { width: 100%; justify-content: center; }
  }
`;

const rentals = [
