  { id: 2, title: "PG Room", location: "Gandhipuram", price: "₹7,000/mo", badge: "Budget Pick", image: "https://images.unsplash.com/photo-1507089947368-19c1da9775ae?w=600&q=80" },
  { id: 3, title: "Office Space", location: "RS Puram", price: "₹25,000/mo", badge: "Premium", image: "https://images.unsplash.com/photo-1497366216548-37526070297c?w=600&q=80" },
];

